import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"实战案例：普光（王献科）辨证全案","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/08-实战案例/01-普光辨证案例.md","filePath":"tcm-data/08-实战案例/01-普光辨证案例.md","lastUpdated":1781084559000}'),i={name:"tcm-data/08-实战案例/01-普光辨证案例.md"};function r(n,t,s,h,g,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="实战案例-普光-王献科-辨证全案" tabindex="-1">实战案例：普光（王献科）辨证全案 <a class="header-anchor" href="#实战案例-普光-王献科-辨证全案" aria-label="Permalink to &quot;实战案例：普光（王献科）辨证全案&quot;">​</a></h1><blockquote><p>案例编号：CASE-20260609-001 辨证日期：2026年6月9日 辨证依据：黄元御《四圣心源》+ 彭子益《圆运动的古中医学》</p></blockquote><hr><h2 id="一、患者信息" tabindex="-1">一、患者信息 <a class="header-anchor" href="#一、患者信息" aria-label="Permalink to &quot;一、患者信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">姓名</td><td style="text-align:left;">王献科（普光）</td></tr><tr><td style="text-align:left;">性别</td><td style="text-align:left;">男</td></tr><tr><td style="text-align:left;">出生</td><td style="text-align:left;">1982年农历正月初三丑时</td></tr><tr><td style="text-align:left;">出生地</td><td style="text-align:left;">山东聊城茌平区</td></tr><tr><td style="text-align:left;">现居</td><td style="text-align:left;">云南大理银桥镇鹤阳新村</td></tr></tbody></table><hr><h2 id="二、症状汇总-按系统" tabindex="-1">二、症状汇总（按系统） <a class="header-anchor" href="#二、症状汇总-按系统" aria-label="Permalink to &quot;二、症状汇总（按系统）&quot;">​</a></h2><p>参见用户原始症状描述，此处按中医辨证归类：</p><h3 id="中焦-脾胃-系统" tabindex="-1">中焦（脾胃）系统 <a class="header-anchor" href="#中焦-脾胃-系统" aria-label="Permalink to &quot;中焦（脾胃）系统&quot;">​</a></h3><ul><li>面色暗沉如覆尘土</li><li>肚皮腰部凉</li><li>腰部赘肉、皮肤暗沉</li><li>头部不自觉前倾</li><li>身体无力不愿动</li></ul><h3 id="肝系统" tabindex="-1">肝系统 <a class="header-anchor" href="#肝系统" aria-label="Permalink to &quot;肝系统&quot;">​</a></h3><ul><li>目干涩、迎风流泪（房事后加重）</li><li>头发花白枯槁</li><li>以前起跳抽筋</li><li>肝脾部偶痛</li></ul><h3 id="相火-上热下寒-系统" tabindex="-1">相火（上热下寒）系统 <a class="header-anchor" href="#相火-上热下寒-系统" aria-label="Permalink to &quot;相火（上热下寒）系统&quot;">​</a></h3><ul><li>血压140/100</li><li>前胸出汗多后背少</li><li>口渴不贪凉</li><li>睡觉露小腿脚</li><li>鼻中生疮（4月）</li></ul><h3 id="下焦-水湿-系统" tabindex="-1">下焦（水湿）系统 <a class="header-anchor" href="#下焦-水湿-系统" aria-label="Permalink to &quot;下焦（水湿）系统&quot;">​</a></h3><ul><li>阴囊腹股沟潮湿</li><li>屁股生疖子</li><li>膝盖阴天痛</li><li>脚后跟开裂</li><li>脚底蜕皮发痒</li></ul><hr><h2 id="三、四诊摘要" tabindex="-1">三、四诊摘要 <a class="header-anchor" href="#三、四诊摘要" aria-label="Permalink to &quot;三、四诊摘要&quot;">​</a></h2><p><strong>缺当面望闻切诊</strong>（舌诊脉诊未能进行），仅以症状分析。</p><hr><h2 id="四、病机结论" tabindex="-1">四、病机结论 <a class="header-anchor" href="#四、病机结论" aria-label="Permalink to &quot;四、病机结论&quot;">​</a></h2><p><strong>水寒土湿木郁 → 相火不降 → 上热下寒</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">病机</th><th style="text-align:left;">症状证据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>本</strong></td><td style="text-align:left;">脾肾阳虚、土湿水寒</td><td style="text-align:left;">腰凉、面色暗沉、无力</td></tr><tr><td style="text-align:left;"><strong>标</strong></td><td style="text-align:left;">肝郁化火、相火不降</td><td style="text-align:left;">血压高、口渴、前胸出汗</td></tr><tr><td style="text-align:left;"><strong>变</strong></td><td style="text-align:left;">湿热下注、瘀血内停</td><td style="text-align:left;">阴囊湿、脚跟裂</td></tr></tbody></table><hr><h2 id="五、处方" tabindex="-1">五、处方 <a class="header-anchor" href="#五、处方" aria-label="Permalink to &quot;五、处方&quot;">​</a></h2><h3 id="温潜黄芽天魂汤" tabindex="-1">温潜黄芽天魂汤 <a class="header-anchor" href="#温潜黄芽天魂汤" aria-label="Permalink to &quot;温潜黄芽天魂汤&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:center;">剂量</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:center;">9g</td><td style="text-align:left;">补中气</td></tr><tr><td style="text-align:left;">炙甘草</td><td style="text-align:center;">6g</td><td style="text-align:left;">培土和中</td></tr><tr><td style="text-align:left;">茯苓</td><td style="text-align:center;">15g</td><td style="text-align:left;">泄湿燥土</td></tr><tr><td style="text-align:left;">干姜</td><td style="text-align:center;">10g</td><td style="text-align:left;">温脾阳</td></tr><tr><td style="text-align:left;">制附子</td><td style="text-align:center;">9g（先煎45min）</td><td style="text-align:left;">温肾阳</td></tr><tr><td style="text-align:left;">桂枝</td><td style="text-align:center;">9g</td><td style="text-align:left;">达肝木</td></tr><tr><td style="text-align:left;">白芍</td><td style="text-align:center;">10g</td><td style="text-align:left;">敛相火</td></tr><tr><td style="text-align:left;">当归</td><td style="text-align:center;">10g</td><td style="text-align:left;">养肝血</td></tr><tr><td style="text-align:left;">制首乌</td><td style="text-align:center;">12g</td><td style="text-align:left;">养肝乌发</td></tr><tr><td style="text-align:left;">生龙骨</td><td style="text-align:center;">15g（先煎）</td><td style="text-align:left;">潜阳</td></tr><tr><td style="text-align:left;">生牡蛎</td><td style="text-align:center;">15g（先煎）</td><td style="text-align:left;">潜阳</td></tr><tr><td style="text-align:left;">泽泻</td><td style="text-align:center;">9g</td><td style="text-align:left;">利湿</td></tr><tr><td style="text-align:left;">丹皮</td><td style="text-align:center;">9g</td><td style="text-align:left;">活血</td></tr><tr><td style="text-align:left;">黄柏</td><td style="text-align:center;">6g</td><td style="text-align:left;">清湿热</td></tr><tr><td style="text-align:left;">怀牛膝</td><td style="text-align:center;">10g</td><td style="text-align:left;">引火下行</td></tr></tbody></table><h3 id="煎服法" tabindex="-1">煎服法 <a class="header-anchor" href="#煎服法" aria-label="Permalink to &quot;煎服法&quot;">​</a></h3><p>附子、龙骨、牡蛎先煎45分钟 → 入余药再煎30分钟 → 二煎25分钟 → 合并分早晚两次温服</p><h3 id="疗程" tabindex="-1">疗程 <a class="header-anchor" href="#疗程" aria-label="Permalink to &quot;疗程&quot;">​</a></h3><p>先服7剂，观察反应</p><hr><h2 id="六、预后判断" tabindex="-1">六、预后判断 <a class="header-anchor" href="#六、预后判断" aria-label="Permalink to &quot;六、预后判断&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">预期变化</th></tr></thead><tbody><tr><td style="text-align:left;">1-2周</td><td style="text-align:left;">湿浊渐化：阴囊潮湿减轻、身体轻快</td></tr><tr><td style="text-align:left;">2-4周</td><td style="text-align:left;">阳气渐复：腰转暖、精力好转、血压趋稳</td></tr><tr><td style="text-align:left;">1-3月</td><td style="text-align:left;">肝血渐充：目干涩改善、面色转润</td></tr><tr><td style="text-align:left;">3-6月</td><td style="text-align:left;">体质转变：尿酸下降、肝肾功能改善</td></tr></tbody></table><hr><h2 id="七、用药前后对比" tabindex="-1">七、用药前后对比 <a class="header-anchor" href="#七、用药前后对比" aria-label="Permalink to &quot;七、用药前后对比&quot;">​</a></h2><p><em>（等待反馈后可在此补充）</em></p><hr><p><em>本案例为中医通鉴数据库的首个实战案例。后续可根据服药反馈持续更新。</em></p>',39)])])}const f=e(i,[["render",r]]);export{y as __pageData,f as default};
